function updateMatrix(matrix, coords, value) {
  const [row, column] = coords
  matrix[row][column] = value
  return matrix
}

function countIf(array, fn) {
  let count = 0
  array.forEach((n) => (fn(n) ? count++ : false))
  return count
}

function fizzbuzz(n: number): string | number {
  if (n % 15 === 0) return 'fizzbuzz'
  if (n % 5 === 0) return 'buzz'
  if (n % 3 === 0) return 'fizz'
  return n
}

function sumMatchingType(a: number | string, b: number | string) {
  if (typeof a === 'number' && typeof b === 'number') {
    return a + b
  }
  return String(Number(a) + Number(b))
}

function getNextTrafficLightColour(light: string): string {
  if (light === 'green') return 'yellow'
  if (light === 'yellow') return 'red'
  return 'green'
}

function greetFullName(firstName, lastName, middleName) {
  if (middleName) {
    return `Hello ${firstName} ${middleName} ${lastName}`
  }
  return `Hello ${firstName} ${lastName}`
}

router.get('/', async (req, res) => {
