export async function up(knex) {
  await knex.schema.createTable('fruits', (table) => {
    table.increments('id').primary()
    table.string('name')
    table.integer('average_grams_each')
    table.string('added_by_user')
  })
}

function scoreGame(frames) {
  let total = 0
  frames.forEach((frame, index) => {
    const next = frames[index + 1]
    if (frame[0] === 10) {
      total += frame[0] + next[0] + next[1]
    } else if (frame[0] + frame[1] === 10) {
      total += frame[0] + frame[1] + next[0]
    } else {
      total += frame[0] + frame[1]
    }
  })
  return total
}

function scoreGame(frames) {
  let total = 0
  frames.forEach((frame, index) => {
    const next = frames[index + 1] || []
    const nextNext = frames[index + 2] || []
    if (index === frames.length - 1) {
      total += frame[0] + frame[1] + (frame[2] || 0)
    } else if (frame[0] === 10 && next[0] === 10) {
      total += frame[0] + next[0] + nextNext[0]
    } else if (frame[0] === 10) {
      total += frame[0] + next[0] + next[1]
    } else if (frame[0] + frame[1] === 10) {
      total += frame[0] + frame[1] + next[0]
    } else {
      total += frame[0] + frame[1]
    }
  })
  return total
}

export async function addFruit(fruit, userId, db = connection) {
  const fruitSnakeCase = {
    name: fruit.name,
    average_grams_each: fruit.averageGramsEach,
    added_by_user: userId,
  }
  return db('fruits')
    .insert(fruitSnakeCase)
    .returning(columns)
    .then((rows) => rows[0])
}

export async function userCanEdit(fruitId, auth0Id, db = connection) {
  return db('fruits')
    .where({ id: fruitId })
    .first()
    .then((fruit) => {
      if (fruit.added_by_user !== auth0Id) {
        throw new Error('Unauthorized')
      }
    })
}

router.put('/:id', checkJwt, async (req, res) => {
  const { fruit } = req.body
  const id = Number(req.params.id)
  try {
    await db.userCanEdit(id, req.auth.sub)
    const updated = await db.updateFruit(id, fruit)
    res.status(200).json({ fruit: updated })
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return res.status(403).send('Unauthorized')
    }
    res.status(500).send('Something went wrong')
  }
})
